insert into public.food_entries (id, title, type, rating, notes, recipe, restaurant_name, city, country, entry_date)
values
  ('11111111-1111-4111-8111-111111111111', 'Olive Oil Squid', 'home', 5, 'Simple, quick, and bright. More lemon next time.', 'Warm olive oil with garlic and chilli. Add squid for a very short cook, then finish with parsley, lemon zest, and toasted bread.', null, 'London', 'United Kingdom', '2026-06-14'),
  ('22222222-2222-4222-8222-222222222222', 'Beef Noodle Soup', 'home', 5, 'Deep broth, soft tendon, a tiny mountain of greens.', 'Braise beef shank with soy, tomato, ginger, star anise, and doubanjiang. Serve with wheat noodles and bok choy.', null, 'London', 'United Kingdom', '2026-06-10'),
  ('33333333-3333-4333-8333-333333333333', 'Cepelinai', 'restaurant', 4, 'Heavy in the best possible way. Sour cream saved the day.', null, 'Senoji Trobele', 'Vilnius', 'Lithuania', '2026-06-03'),
  ('44444444-4444-4444-8444-444444444444', 'Cold Beet Soup', 'travel', 5, 'Pink, cold, gentle. A perfect hot-day lunch.', null, 'Amandus', 'Vilnius', 'Lithuania', '2026-05-30'),
  ('55555555-5555-4555-8555-555555555555', 'Tomato Salami Pasta', 'home', 4, 'The weeknight one. Salty edges, glossy sauce.', 'Render salami, bloom garlic and chilli, add crushed tomato, finish pasta in the sauce with parmesan.', null, 'London', 'United Kingdom', '2026-05-24'),
  ('66666666-6666-4666-8666-666666666666', 'Taiwanese Fried Chicken', 'home', 5, 'Basil crackle. Five-spice dust everywhere.', 'Marinate chicken thigh in soy, garlic, ginger, and five spice. Coat with sweet potato starch, fry twice, and toss with fried basil.', null, 'London', 'United Kingdom', '2026-05-18'),
  ('77777777-7777-4777-8777-777777777777', 'Mushroom Risotto', 'home', 4, 'Creamy without cream. Good rainy-night food.', 'Toast rice, deglaze with white wine, ladle in mushroom stock, finish with butter, parmesan, and thyme mushrooms.', null, 'London', 'United Kingdom', '2026-05-13'),
  ('88888888-8888-4888-8888-888888888888', 'Smoked Eel', 'restaurant', 5, 'Silky, smoky, tiny and memorable.', null, '40 Maltby Street', 'London', 'United Kingdom', '2026-05-08'),
  ('99999999-9999-4999-8999-999999999999', 'Sourdough Breakfast', 'home', 4, 'Jam, salted butter, strong coffee.', null, null, 'London', 'United Kingdom', '2026-04-29'),
  ('aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa', 'Sesame Noodles', 'home', 5, 'Cold, nutty, almost too easy.', 'Whisk sesame paste, soy, black vinegar, chilli oil, sugar, and noodle water. Toss with cold noodles and cucumber.', null, 'London', 'United Kingdom', '2026-04-22'),
  ('bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb', 'Dumpling Sunday', 'home', 5, 'A quiet afternoon of folding, then steam on the windows.', 'Pork, cabbage, ginger, white pepper, and sesame oil. Pan-fry until the bottoms are crisp.', null, 'London', 'United Kingdom', '2026-04-14'),
  ('cccccccc-cccc-4ccc-8ccc-cccccccccccc', 'Grilled Mackerel', 'home', 4, 'Charred skin, cucumber, rice. Very clean.', 'Salt mackerel for 20 minutes, grill hot, serve with rice, grated ginger, cucumber, and lemon.', null, 'London', 'United Kingdom', '2026-04-04'),
  ('dddddddd-dddd-4ddd-8ddd-dddddddddddd', 'Ricotta Ravioli', 'restaurant', 4, 'Soft pasta, lemon butter, a tiny luxury.', null, 'Padella', 'London', 'United Kingdom', '2026-03-28'),
  ('eeeeeeee-eeee-4eee-8eee-eeeeeeeeeeee', 'Taiwanese Breakfast Roll', 'home', 5, 'Egg, scallions, crisp edges, eaten standing up.', 'Pan-fry scallion pancake, add egg, cheese if wanted, and roll with soy paste.', null, 'London', 'United Kingdom', '2026-03-20'),
  ('ffffffff-ffff-4fff-8fff-ffffffffffff', 'Cardamom Bun', 'travel', 4, 'Sticky fingers, cold hands, good coffee.', null, 'Taste Map', 'Vilnius', 'Lithuania', '2026-03-12'),
  ('12121212-1212-4121-8121-121212121212', 'Summer Tomatoes', 'home', 5, 'Tomatoes, salt, olive oil. Nothing else needed.', null, null, 'London', 'United Kingdom', '2026-02-25'),
  ('13131313-1313-4131-8131-131313131313', 'Roast Duck Rice', 'restaurant', 4, 'Glossy skin, ginger-scallion sauce, very fast joy.', null, 'Four Seasons', 'London', 'United Kingdom', '2026-02-10'),
  ('14141414-1414-4141-8141-141414141414', 'Clams with Basil', 'home', 5, 'A little wok smoke, a lot of basil.', 'Steam clams with ginger, garlic, rice wine, soy, chilli, and basil. Serve immediately.', null, 'London', 'United Kingdom', '2026-01-27'),
  ('15151515-1515-4151-8151-151515151515', 'Pumpkin Soup', 'home', 3, 'Soft and sweet. Needed chilli oil.', 'Roast pumpkin with onion, blend with stock, finish with yoghurt and seeds.', null, 'London', 'United Kingdom', '2026-01-13'),
  ('16161616-1616-4161-8161-161616161616', 'Brown Butter Gnocchi', 'home', 4, 'Sage, brown butter, soft pillows.', 'Pan-fry gnocchi in brown butter with sage. Add lemon, parmesan, and black pepper.', null, 'London', 'United Kingdom', '2025-12-21'),
  ('17171717-1717-4171-8171-171717171717', 'Oyster Night', 'restaurant', 5, 'Cold shells, hot chips, small celebration.', null, 'The Quality Chop House', 'London', 'United Kingdom', '2025-12-08'),
  ('18181818-1818-4181-8181-181818181818', 'Kibinai', 'travel', 4, 'Warm pastry after the lake walk.', null, 'Trakai Kybynlar', 'Trakai', 'Lithuania', '2025-11-19'),
  ('19191919-1919-4191-8191-191919191919', 'Mapo Tofu', 'home', 5, 'Numbing, red, very rice-hungry.', 'Fry doubanjiang, garlic, ginger, pork, and tofu. Finish with chilli oil, scallions, and toasted Sichuan pepper.', null, 'London', 'United Kingdom', '2025-11-07'),
  ('20202020-2020-4202-8202-202020202020', 'Lemony Beans', 'home', 4, 'Olive oil, herbs, enough lemon to wake it up.', 'Simmer white beans with garlic, bay, and stock. Finish with lemon, parsley, and olive oil.', null, 'London', 'United Kingdom', '2025-10-18')
on conflict (id) do nothing;

update public.food_entries
set want_to_recreate = true
where id in (
  '33333333-3333-4333-8333-333333333333',
  '44444444-4444-4444-8444-444444444444',
  'dddddddd-dddd-4ddd-8ddd-dddddddddddd',
  'ffffffff-ffff-4fff-8fff-ffffffffffff'
);

update public.food_entries
set type = 'recipe', cook_time_minutes = 16
where id = 'aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa';

update public.food_entries
set cook_time_minutes = case id
  when '11111111-1111-4111-8111-111111111111' then 18
  when '22222222-2222-4222-8222-222222222222' then 180
  when '55555555-5555-4555-8555-555555555555' then 28
  when '66666666-6666-4666-8666-666666666666' then 55
  when '77777777-7777-4777-8777-777777777777' then 42
  when 'bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb' then 75
  when 'cccccccc-cccc-4ccc-8ccc-cccccccccccc' then 30
  when 'eeeeeeee-eeee-4eee-8eee-eeeeeeeeeeee' then 12
  when '14141414-1414-4141-8141-141414141414' then 22
  when '15151515-1515-4151-8151-151515151515' then 45
  when '16161616-1616-4161-8161-161616161616' then 24
  when '19191919-1919-4191-8191-191919191919' then 26
  when '20202020-2020-4202-8202-202020202020' then 32
  else cook_time_minutes
end;

insert into public.tags (name)
values
  ('Home'), ('Restaurant'), ('Travel'), ('Taiwanese'), ('Lithuanian'), ('Italian'), ('Seafood'), ('Comfort'),
  ('Quick'), ('Summer'), ('Winter'), ('Favorites'), ('Vegetarian'), ('Light'), ('Rich'), ('London'), ('Vilnius'),
  ('Cafe'), ('Breakfast'), ('Pasta'), ('Favorite'), ('Want to recreate')
on conflict (name) do nothing;

insert into public.photos (food_entry_id, image_url, thumbnail_url)
select id,
  'https://images.unsplash.com/photo-1498837167922-ddd27525d352?auto=format&fit=crop&w=900&h=1200&q=82',
  'https://images.unsplash.com/photo-1498837167922-ddd27525d352?auto=format&fit=crop&w=420&h=560&q=72'
from public.food_entries
where not exists (
  select 1 from public.photos where public.photos.food_entry_id = public.food_entries.id
);

